import{_ as e,o as a,c as o,a2 as n}from"./chunks/framework.DeNJmwJc.js";const u=JSON.parse('{"title":"Chapter 13 — File Motions","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/13-file-motions.md","filePath":"chapters/13-file-motions.md"}'),s={name:"chapters/13-file-motions.md"};function d(r,t,i,l,c,p){return a(),o("div",null,[...t[0]||(t[0]=[n(`<h1 id="chapter-13-—-file-motions" tabindex="-1">Chapter 13 — File Motions <a class="header-anchor" href="#chapter-13-—-file-motions" aria-label="Permalink to &quot;Chapter 13 — File Motions&quot;">​</a></h1><blockquote><p><em>&quot;Jump across hundreds of lines in a single keystroke.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐ Beginner-Intermediate <strong>Estimated Reading Time:</strong> 15–20 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Word and line motions are fast—but what if you need to jump from line 5 to line 500?</p><p>File motions let you navigate across an entire file instantly.</p><hr><h1 id="top-and-bottom-of-file" tabindex="-1">Top and Bottom of File <a class="header-anchor" href="#top-and-bottom-of-file" aria-label="Permalink to &quot;Top and Bottom of File&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Motion</th><th>Action</th></tr></thead><tbody><tr><td><code>gg</code></td><td>Jump to <strong>first line</strong> of file</td></tr><tr><td><code>G</code></td><td>Jump to <strong>last line</strong> of file</td></tr></tbody></table><h2 id="with-count" tabindex="-1">With Count <a class="header-anchor" href="#with-count" aria-label="Permalink to &quot;With Count&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Motion</th><th>Action</th></tr></thead><tbody><tr><td><code>42G</code></td><td>Jump to line 42</td></tr><tr><td><code>42gg</code></td><td>Jump to line 42</td></tr><tr><td><code>:42</code></td><td>Jump to line 42</td></tr><tr><td><code>50%</code></td><td>Jump to 50% of file</td></tr></tbody></table><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>gg      →   go to line 1</span></span>
<span class="line"><span>G       →   go to last line</span></span>
<span class="line"><span>100gg   →   go to line 100</span></span>
<span class="line"><span>:200    →   go to line 200 (command mode)</span></span></code></pre></div><hr><h1 id="screen-based-jumps" tabindex="-1">Screen-Based Jumps <a class="header-anchor" href="#screen-based-jumps" aria-label="Permalink to &quot;Screen-Based Jumps&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Motion</th><th>Action</th></tr></thead><tbody><tr><td><code>H</code></td><td>Jump to <strong>top</strong> of screen</td></tr><tr><td><code>M</code></td><td>Jump to <strong>middle</strong> of screen</td></tr><tr><td><code>L</code></td><td>Jump to <strong>bottom</strong> of screen</td></tr></tbody></table><p>These are relative to what&#39;s currently visible.</p><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Screen content (visible):</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌──────────────────────┐</span></span>
<span class="line"><span>│ Line 1               │ ← H (top of screen)</span></span>
<span class="line"><span>│ Line 2               │</span></span>
<span class="line"><span>│ Line 3               │</span></span>
<span class="line"><span>│ Line 4               │</span></span>
<span class="line"><span>│ Line 5               │ ← M (middle of screen)</span></span>
<span class="line"><span>│ Line 6               │</span></span>
<span class="line"><span>│ Line 7               │</span></span>
<span class="line"><span>│ Line 8               │</span></span>
<span class="line"><span>│ Line 9               │ ← L (bottom of screen)</span></span>
<span class="line"><span>└──────────────────────┘</span></span></code></pre></div><hr><h1 id="scrolling" tabindex="-1">Scrolling <a class="header-anchor" href="#scrolling" aria-label="Permalink to &quot;Scrolling&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Motion</th><th>Action</th></tr></thead><tbody><tr><td><code>Ctrl+u</code></td><td>Scroll <strong>up</strong> half page</td></tr><tr><td><code>Ctrl+d</code></td><td>Scroll <strong>down</strong> half page</td></tr><tr><td><code>Ctrl+b</code></td><td>Scroll <strong>up</strong> full page</td></tr><tr><td><code>Ctrl+f</code></td><td>Scroll <strong>down</strong> full page</td></tr><tr><td><code>Ctrl+y</code></td><td>Scroll up one line</td></tr><tr><td><code>Ctrl+e</code></td><td>Scroll down one line</td></tr></tbody></table><h2 id="centering-the-cursor" tabindex="-1">Centering the Cursor <a class="header-anchor" href="#centering-the-cursor" aria-label="Permalink to &quot;Centering the Cursor&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Motion</th><th>Action</th></tr></thead><tbody><tr><td><code>zz</code></td><td>Center cursor vertically on screen</td></tr><tr><td><code>zt</code></td><td>Move cursor to <strong>top</strong> of screen</td></tr><tr><td><code>zb</code></td><td>Move cursor to <strong>bottom</strong> of screen</td></tr></tbody></table><p>These do not move the cursor in the file—they move the viewport.</p><hr><h1 id="the-jump-list" tabindex="-1">The Jump List <a class="header-anchor" href="#the-jump-list" aria-label="Permalink to &quot;The Jump List&quot;">​</a></h1><p>Vim keeps a <strong>jump list</strong> — a history of cursor positions.</p><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>Ctrl+o</code></td><td>Jump to <strong>previous</strong> position</td></tr><tr><td><code>Ctrl+i</code></td><td>Jump to <strong>next</strong> position</td></tr></tbody></table><h2 id="key-insight" tabindex="-1">Key Insight <a class="header-anchor" href="#key-insight" aria-label="Permalink to &quot;Key Insight&quot;">​</a></h2><p>Every time you make a &quot;big&quot; jump (e.g., <code>gg</code>, <code>G</code>, search, line number jump), Vim saves the previous position in the jump list.</p><p>You can think of <code>Ctrl+o</code> as &quot;go back&quot; and <code>Ctrl+i</code> as &quot;go forward.&quot;</p><hr><h1 id="the-change-list" tabindex="-1">The Change List <a class="header-anchor" href="#the-change-list" aria-label="Permalink to &quot;The Change List&quot;">​</a></h1><p>Vim also tracks where you made changes:</p><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>g;</code></td><td>Go to <strong>previous</strong> change position</td></tr><tr><td><code>g,</code></td><td>Go to <strong>next</strong> change position</td></tr></tbody></table><p>Useful when you need to revisit recently edited areas.</p><hr><h1 id="marks" tabindex="-1">Marks <a class="header-anchor" href="#marks" aria-label="Permalink to &quot;Marks&quot;">​</a></h1><p>You can set custom waypoints in a file:</p><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>ma</code></td><td>Set mark named <code>a</code></td></tr><tr><td><code>&#39;a</code></td><td>Jump to line of mark <code>a</code></td></tr><tr><td><code>\`a</code></td><td>Jump to exact position of mark <code>a</code></td></tr></tbody></table><p>Marks can be lowercase (file-local) or uppercase (global across files).</p><hr><h1 id="percent-jump" tabindex="-1">Percent Jump <a class="header-anchor" href="#percent-jump" aria-label="Permalink to &quot;Percent Jump&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Motion</th><th>Action</th></tr></thead><tbody><tr><td><code>%</code></td><td>Jump to matching bracket/brace/paren</td></tr></tbody></table><p>This is extremely useful for code:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>if (condition) {</span></span>
<span class="line"><span>    // cursor here</span></span>
<span class="line"><span>    ...</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Press <code>%</code> → jump to the matching <code>{</code> or <code>}</code>.</p><hr><h1 id="practical-example" tabindex="-1">Practical Example <a class="header-anchor" href="#practical-example" aria-label="Permalink to &quot;Practical Example&quot;">​</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You&#39;re at line 10.</span></span>
<span class="line"><span>You need to go to line 350.</span></span>
<span class="line"><span>Then back to line 10.</span></span>
<span class="line"><span>Then to the matching bracket.</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>350G        →   jump to line 350</span></span>
<span class="line"><span>Ctrl+o      →   back to line 10</span></span>
<span class="line"><span>%           →   jump to matching bracket</span></span>
<span class="line"><span>Ctrl+i      →   forward again</span></span></code></pre></div><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Motion</th><th>Action</th></tr></thead><tbody><tr><td><code>gg</code></td><td>First line</td></tr><tr><td><code>G</code></td><td>Last line</td></tr><tr><td><code>42G</code></td><td>Specific line</td></tr><tr><td><code>H</code>/<code>M</code>/<code>L</code></td><td>Screen top/mid/bottom</td></tr><tr><td><code>Ctrl+u/d</code></td><td>Scroll half page</td></tr><tr><td><code>Ctrl+o/i</code></td><td>Jump list back/forward</td></tr><tr><td><code>%</code></td><td>Matching bracket</td></tr><tr><td><code>zz</code></td><td>Center screen</td></tr></tbody></table><hr><h1 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h1><ul><li><code>gg</code> and <code>G</code> jump to the very beginning and end of a file.</li><li>Use <code>:42</code> or <code>42G</code> to jump to a specific line number.</li><li><code>Ctrl+o</code> / <code>Ctrl+i</code> navigate through your jump history.</li><li><code>%</code> jumps between matching brackets—invaluable for coding.</li><li><code>zz</code> centers the screen without moving the cursor in the file.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Open a large file (500+ lines) and jump from top to bottom using <code>gg</code> and <code>G</code>.</li><li>Jump to line 250 using <code>250G</code>.</li><li>Scroll through the file using <code>Ctrl+d</code> and <code>Ctrl+u</code>.</li><li>Set a mark with <code>ma</code>, jump somewhere else, return with <code>&#39;a</code>.</li><li>Use <code>Ctrl+o</code> and <code>Ctrl+i</code> to navigate your jump history.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./14-searching.html"><strong>Chapter 14 — Searching</strong></a></p><p>Find any word or pattern in your file instantly using Vim&#39;s powerful search features.</p>`,67)])])}const m=e(s,[["render",d]]);export{u as __pageData,m as default};
